#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        int mism = 0;
        for (int i = 0; i < N/2; ++i) {
            if (s[i] != s[N-1-i]) mism++;
        }
        if (mism % 2 == 0 || N % 2 == 1) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

