#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    t = int(next(it))
    out = []
    for _ in range(t):
        n = int(next(it))
        s = next(it).strip()
        mism = sum(1 for i in range(n//2) if s[i] != s[n-1-i])
        if mism % 2 == 0 or n % 2 == 1:
            out.append("YES")
        else:
            out.append("NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

